import{_ as a,o as t,c as r,a2 as i}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"Security","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/security.md","filePath":"en/guide/security.md"}'),o={name:"en/guide/security.md"};function s(n,e,c,l,d,h){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h1><p>Clearance went through a dedicated pre-publication security audit plus two follow-up hardening passes before release. Highlights: privilege-escalation ceilings on every permission-granting path (direct grants and role-level syncing alike), deny-authoritative context overrides, an allow-list SVG sanitizer, a protected <code>clearance-*</code> permission namespace, and guest-safe Blade directives.</p><h2 id="panel-access-fine-grained-write-permissions" tabindex="-1">Panel access &amp; fine-grained write permissions <a class="header-anchor" href="#panel-access-fine-grained-write-permissions" aria-label="Permalink to &quot;Panel access &amp; fine-grained write permissions&quot;">​</a></h2><p>Read access to the whole panel requires the <code>clearance-access</code> permission (checked via <code>can()</code>, never <code>hasRole()</code>). Write operations on each section are gated by a dedicated, delegable permission - all created by <code>clearance:install</code> and assigned to <code>super_admin</code>:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Controls</th></tr></thead><tbody><tr><td><code>clearance-permissions-write</code></td><td>Create / edit / delete permissions</td></tr><tr><td><code>clearance-roles-write</code></td><td>Create / edit / delete roles and their permission assignments</td></tr><tr><td><code>clearance-guards-write</code></td><td>Create / edit / delete guards</td></tr><tr><td><code>clearance-settings-write</code></td><td>Edit display metadata, icons, colors, default role</td></tr><tr><td><code>clearance-users-write</code></td><td>Assign / remove roles for a specific user</td></tr></tbody></table><p>If a fine-grained permission row doesn&#39;t exist at all in the database (a legacy pre-seeding state), the check falls back to <code>clearance-access</code> for backwards compatibility.</p><h2 id="protected-clearance-namespace" tabindex="-1">Protected <code>clearance-*</code> namespace <a class="header-anchor" href="#protected-clearance-namespace" aria-label="Permalink to &quot;Protected `clearance-*` namespace&quot;">​</a></h2><p><code>clearance-*</code> permissions are reserved: they cannot be created, renamed, deleted, or added to any role except through the package&#39;s own install flow - even by a <code>super_admin</code> actor for the <code>super_admin</code> role itself.</p><h2 id="privilege-escalation-ceilings" tabindex="-1">Privilege-escalation ceilings <a class="header-anchor" href="#privilege-escalation-ceilings" aria-label="Permalink to &quot;Privilege-escalation ceilings&quot;">​</a></h2><p>Every permission-granting path in Clearance enforces a ceiling so an actor can never grant more than they themselves hold:</p><ul><li><strong>Ceiling roles</strong> - a role can declare a parent role whose permission set acts as an upper bound. Any excess permission is silently trimmed on <code>RoleService::setParent()</code> and on every subsequent permission sync - no exception, no error message. Removing permissions from a parent cascades the removal to every child automatically. See <a href="/clearance-docs/en/features/roles.html">Roles</a> for the full ceiling API.</li><li><strong>Users module</strong> - both role assignment and direct/override permission grants enforce a privilege ceiling: a non-<code>super_admin</code> actor cannot modify their own assignments, and cannot grant a permission they don&#39;t themselves hold. See <a href="/clearance-docs/en/features/users.html">Users</a>.</li></ul><h2 id="deny-authoritative-context-overrides" tabindex="-1">Deny-authoritative context overrides <a class="header-anchor" href="#deny-authoritative-context-overrides" aria-label="Permalink to &quot;Deny-authoritative context overrides&quot;">​</a></h2><p>Per-context permission overrides (<code>clr_ctx_overrides</code>) support <code>forced_on</code> and <code>forced_off</code>. <code>forced_off</code> always wins - even over a permission granted by a global role. There is no path that lets a lower-precedence grant override an explicit deny. See <a href="/clearance-docs/en/guide/architecture.html#how-resolution-works">Architecture</a> for the full resolution order.</p><h2 id="svg-sanitization" tabindex="-1">SVG sanitization <a class="header-anchor" href="#svg-sanitization" aria-label="Permalink to &quot;SVG sanitization&quot;">​</a></h2><p>Every user-supplied icon (role/guard display metadata in the Settings panel) passes through an allow-list sanitizer both before storage and at render time - not a one-time check at upload.</p><h2 id="guest-safe-blade-directives" tabindex="-1">Guest-safe Blade directives <a class="header-anchor" href="#guest-safe-blade-directives" aria-label="Permalink to &quot;Guest-safe Blade directives&quot;">​</a></h2><p><code>@canin</code> and <code>@hasrolein</code> both resolve safely (return <code>false</code>) for a guest user - they never throw.</p><h2 id="gate-bypass-is-application-wide" tabindex="-1">Gate bypass is application-wide <a class="header-anchor" href="#gate-bypass-is-application-wide" aria-label="Permalink to &quot;Gate bypass is application-wide&quot;">​</a></h2><p><code>super_admin_gate_bypass</code> (default <code>false</code>) controls whether the <code>super_admin</code> role bypasses all Laravel <code>can()</code> / <code>Gate::allows()</code> / policy checks globally, via a <code>Gate::before()</code> hook.</p><div class="warning custom-block"><p class="custom-block-title">Not scoped to the panel</p><p>When enabled, any user holding <code>super_admin</code> skips all Gate checks application-wide - not only Clearance panel checks. Enable it deliberately. See <a href="/clearance-docs/en/features/super-admin.html">Super Admin</a> for alias detection and promotion behavior.</p></div><h2 id="security-relevant-gotchas" tabindex="-1">Security-relevant gotchas <a class="header-anchor" href="#security-relevant-gotchas" aria-label="Permalink to &quot;Security-relevant gotchas&quot;">​</a></h2><ul><li><code>forced_off</code> always wins - even over a permission granted by a global role.</li><li>A ceiling role only trims, never grants - setting a permissive parent grants the child nothing by itself.</li><li>The Gate bypass (<code>super_admin_gate_bypass</code>) is application-wide, not panel-scoped.</li><li>The Users module is off by default (<code>modules.users = false</code>).</li><li><code>clearance-*</code> permissions are untouchable outside the install flow, even for <code>super_admin</code>.</li><li>Always run <code>clearance:install</code>, not a plain <code>migrate</code>, on a fresh setup - see <a href="/clearance-docs/en/guide/installation.html">Installation</a>.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/clearance-docs/en/guide/architecture.html">Architecture</a> - resolution precedence and the <code>clr_*</code> schema</li><li><a href="/clearance-docs/en/features/roles.html">Roles</a> - ceiling roles in depth</li><li><a href="/clearance-docs/en/features/users.html">Users</a> - the privilege ceiling on role/permission assignment</li><li><a href="/clearance-docs/en/features/super-admin.html">Super Admin</a> - Gate bypass and alias detection</li></ul>',24)])])}const m=a(o,[["render",s]]);export{u as __pageData,m as default};
